-- ============================================================
-- sql_fix.sql — Autoflow Schema Migration Patches
-- Run all statements in sequence. Safe to re-run (IF NOT EXISTS / IGNORE guards).
-- Generated by audit Phase 33–onwards
-- ============================================================

-- [P34-A3] web_properties now requires workspace_id column.
-- If the column doesn't already exist, add it.
ALTER TABLE `web_properties`
    ADD COLUMN IF NOT EXISTS `workspace_id` INT UNSIGNED NOT NULL DEFAULT 1
        COMMENT 'Workspace isolation — added P34' AFTER `id`;

-- Backfill existing rows to workspace 1 (root) if NULL
UPDATE `web_properties` SET `workspace_id` = 1 WHERE `workspace_id` IS NULL OR `workspace_id` = 0;

-- Add index for workspace-scoped list queries
ALTER TABLE `web_properties`
    ADD INDEX IF NOT EXISTS `idx_prop_workspace` (`workspace_id`);

-- [P35-T1] Backfill subscribers auto-created by web tracking with NULL workspace_id.
-- These were created by track.php's identify event handler before the workspace_id fix.
-- We assign them to workspace 1 (root) as a safe default.
-- After running this, verify by: SELECT id, email FROM subscribers WHERE workspace_id IS NULL;
UPDATE `subscribers` s
JOIN `web_properties` wp ON wp.id = s.property_id
SET s.workspace_id = wp.workspace_id
WHERE s.workspace_id IS NULL AND s.source = 'website_tracking' AND s.property_id IS NOT NULL;

-- Any remaining NULL workspace_id subscribers (no property_id linkage) → workspace 1
UPDATE `subscribers` SET `workspace_id` = 1 WHERE `workspace_id` IS NULL;

