-- Used in: every chat history fetch
-- Pattern: WHERE conversation_id = ? ORDER BY created_at ASC
ALTER TABLE `ai_org_messages`
    ADD INDEX IF NOT EXISTS `idx_aom_conv_date` (`conversation_id`, `created_at`);

-- [P40-IDX4] ai_workspace_files: conversation_id (file listing per session)
-- Used in: workspace_list, workspace_delete (every workspace operation)
-- Pattern: WHERE conversation_id = ? OR conversation_id = ?
ALTER TABLE `ai_workspace_files`
    ADD INDEX IF NOT EXISTS `idx_awf_conversation` (`conversation_id`);

-- [P40-IDX5] ai_training_docs: property_id + status + is_active
-- Used in: list_docs, worker train_pending (hot path)
-- Pattern: WHERE property_id = ? AND is_active = 1 AND status IN ('pending', 'error')
ALTER TABLE `ai_training_docs`
    ADD INDEX IF NOT EXISTS `idx_atd_prop_status_active` (`property_id`, `status`, `is_active`);

-- [P40-IDX6] ai_training_chunks: property_id (RAG search + BM25 scoring)
-- Used in: every AI chat query similarity search (highest traffic)
-- Pattern: WHERE property_id = ? ORDER BY ... (vector search)
ALTER TABLE `ai_training_chunks`
    ADD INDEX IF NOT EXISTS `idx_atc_property` (`property_id`);

-- [P40-IDX7] ai_org_users: admin_id + status (org user listing)
-- Used in: ai_org_users.php list action (every org management page load)
-- Pattern: WHERE admin_id = ? OR id = ? ORDER BY created_at DESC
ALTER TABLE `ai_org_users`
    ADD INDEX IF NOT EXISTS `idx_aou_admin_status` (`admin_id`, `status`);

-- [P40-IDX8] ai_org_access_tokens: user_id + is_active + expires_at (token auth)
-- Used in: requireAISpaceAuth() Bearer token validation
-- Pattern: WHERE token = ? AND expires_at > NOW() AND is_active = 1
ALTER TABLE `ai_org_access_tokens`
    ADD INDEX IF NOT EXISTS `idx_aoat_user_active_exp` (`user_id`, `is_active`, `expires_at`);

-- [P40-IDX9] global_assets: conversation_id + is_deleted (workspace asset list)
-- Pattern: WHERE (conversation_id = ? OR conversation_id = ?) AND is_deleted = 0
ALTER TABLE `global_assets`
    ADD INDEX IF NOT EXISTS `idx_ga_conv_deleted` (`conversation_id`, `is_deleted`);

-- [P40-S1] SECURITY: Ensure ai_org_users has updated_at column
-- Needed for row-level audit without full table scan in large orgs
ALTER TABLE `ai_org_users`
    ADD COLUMN IF NOT EXISTS `updated_at` DATETIME NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP AFTER `created_at`;

-- [P40-S2] SECURITY: Ensure ai_feedback table exists (created lazily in code,
-- but explicit schema definition ensures FK-readiness and correct collation)
CREATE TABLE IF NOT EXISTS `ai_feedback` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `org_user_id` INT NULL,
    `category_id` VARCHAR(100) NULL,
    `property_id` VARCHAR(100) NULL,
    `conversation_id` VARCHAR(255) NULL,
    `type` ENUM('bug','suggestion','praise','other') NOT NULL DEFAULT 'other',
    `title` VARCHAR(255) NOT NULL,
    `description` TEXT NOT NULL,
    `screenshot_url` VARCHAR(1000) NULL,
    `page_url` VARCHAR(1000) NULL,
    `user_agent` VARCHAR(512) NULL,
    `status` ENUM('new','in_review','resolved','closed') NOT NULL DEFAULT 'new',
    `admin_note` TEXT NULL,
    `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    `updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX `idx_aif_status` (`status`),
    INDEX `idx_aif_type` (`type`),
    INDEX `idx_aif_org_user` (`org_user_id`),
    INDEX `idx_aif_property` (`property_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

